const body = $input.first().json.body;
const msg = body?.data?.message;
const key = body?.data?.key;

if (!msg || key?.fromMe) return [];

const phone = (key?.remoteJid || '').replace('@s.whatsapp.net', '').replace('@g.us', '');
const text = msg?.conversation || msg?.extendedTextMessage?.text || '';
const pushName = body?.data?.pushName || '';
const timestamp = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

if (!phone || !text) return [];

return [{ json: { phone, text, pushName, timestamp, raw: body } }];

const text = $input.first().json.text.toLowerCase();

const intents = [
  { intent: 'QUOTE_REQUEST', keywords: ['price', 'quote', 'cost', 'budget', 'how much', 'preco', 'orcamento', 'valor', 'quanto'] },
  { intent: 'SUPPORT', keywords: ['problem', 'broken', 'not working', 'help', 'issue', 'erro', 'problema', 'nao funciona', 'ajuda'] },
  { intent: 'SCHEDULING', keywords: ['schedule', 'appointment', 'visit', 'when', 'agendar', 'visita', 'horario', 'disponivel'] },
  { intent: 'GENERAL_INFO', keywords: ['info', 'details', 'what do you', 'services', 'informacao', 'servicos', 'o que voce'] }
];

let detected = 'UNKNOWN';
for (const { intent, keywords } of intents) {
  if (keywords.some(k => text.includes(k))) {
    detected = intent;
    break;
  }
}

return [{ json: { ...$input.first().json, intent: detected } }];
